def gen(rng, size):
    n = max(1, size)
    arr = [rng.randint(-4, 4)]
    for _ in range(n - 1):
        arr.append(rng.randint(-4, 4) if rng.random() < 0.85 else None)
    while arr and arr[-1] is None:
        arr.pop()
    target = rng.randint(-3, 3)
    return [arr, target]

