class Solution:
    def pathSum(self, root, targetSum):
        # brute force: for every node, count downward paths starting there
        def count_from(node, remaining):
            if not node:
                return 0
            total = 1 if node.val == remaining else 0
            total += count_from(node.left, remaining - node.val)
            total += count_from(node.right, remaining - node.val)
            return total
        def each(node):
            if not node:
                return 0
            return count_from(node, targetSum) + each(node.left) + each(node.right)
        return each(root)

