var pathSum = function(root, targetSum) {
    const prefix = new Map();
    prefix.set(0, 1);
    let count = 0;
    function dfs(node, running) {
        if (!node) return;
        running += node.val;
        count += prefix.get(running - targetSum) || 0;
        prefix.set(running, (prefix.get(running) || 0) + 1);
        dfs(node.left, running);
        dfs(node.right, running);
        prefix.set(running, prefix.get(running) - 1);
    }
    dfs(root, 0);
    return count;
};
